@* Displays a single task with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <div class="d-flex justify-content-between align-items-start mb-1">
            <h6 class="card-title mb-0">@Task.Title</h6>
            <span class="badge @PriorityClass">@Task.Priority</span>
        </div>
        <p class="card-text text-muted small mb-1">@Task.Assignee</p>
        <p class="card-text small mb-2">@Task.DueDate.ToString("MMM dd")</p>
        <div class="d-flex justify-content-between">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@isSaving">
                @(isSaving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter]
    public EventCallback OnCancel { get; set; }

    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
            ResetForm();
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        ResetForm();
        await OnCancel.InvokeAsync();
    }

    private void ResetForm()
    {
        title = string.Empty;
        assignee = string.Empty;
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }
}

@* A single Kanban column displaying its header, task cards, and an add-task form toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => HandleMoveLeft(task)"
                          OnMoveRight="() => HandleMoveRight(task)" />
            }

            @if (showAddForm)
            {
                <AddTaskForm Status="@Status"
                             TaskService="TaskService"
                             OnTaskCreated="HandleTaskCreated"
                             OnCancel="() => showAddForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = default!;

    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public string? LeftStatus { get; set; }

    [Parameter]
    public string? RightStatus { get; set; }

    [Parameter]
    public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private bool showAddForm;

    private async Task HandleMoveLeft(TaskItem task)
    {
        if (LeftStatus is not null)
        {
            await OnTaskMoved.InvokeAsync((task.Id, LeftStatus));
        }
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        if (RightStatus is not null)
        {
            await OnTaskMoved.InvokeAsync((task.Id, RightStatus));
        }
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        showAddForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

@* Search input for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter]
    public string SearchText { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats TotalCount="allTasks.Count"
                ToDoCount="todoTasks.Count"
                InProgressCount="inProgressTasks.Count"
                DoneCount="doneTasks.Count"
                OverdueCount="overdueTasks.Count" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Status="To Do"
                      Tasks="filteredTodo"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      RightStatus="In Progress"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="HandleTaskCreated"
                      TaskService="TaskService" />

        <KanbanColumn ColumnName="In Progress"
                      Status="In Progress"
                      Tasks="filteredInProgress"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      LeftStatus="To Do"
                      RightStatus="Done"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="HandleTaskCreated"
                      TaskService="TaskService" />

        <KanbanColumn ColumnName="Done"
                      Status="Done"
                      Tasks="filteredDone"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      LeftStatus="In Progress"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="HandleTaskCreated"
                      TaskService="TaskService" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    // Unfiltered lists by status (used for stats)
    private List<TaskItem> todoTasks = new();
    private List<TaskItem> inProgressTasks = new();
    private List<TaskItem> doneTasks = new();
    private List<TaskItem> overdueTasks = new();

    // Filtered lists by search (used for display)
    private List<TaskItem> filteredTodo = new();
    private List<TaskItem> filteredInProgress = new();
    private List<TaskItem> filteredDone = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
            CategorizeAndFilter();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void CategorizeAndFilter()
    {
        todoTasks = allTasks.Where(t => t.Status == "To Do").ToList();
        inProgressTasks = allTasks.Where(t => t.Status == "In Progress").ToList();
        doneTasks = allTasks.Where(t => t.Status == "Done").ToList();
        overdueTasks = allTasks.Where(t => t.DueDate < DateTime.Today).ToList();

        ApplySearchFilter();
    }

    private void ApplySearchFilter()
    {
        filteredTodo = FilterBySearch(todoTasks);
        filteredInProgress = FilterBySearch(inProgressTasks);
        filteredDone = FilterBySearch(doneTasks);
    }

    private List<TaskItem> FilterBySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;

        return tasks
            .Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }

    private void HandleSearchChanged(string newSearch)
    {
        searchText = newSearch;
        ApplySearchFilter();
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) move)
    {
        await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);

        var task = allTasks.First(t => t.Id == move.TaskId);
        var index = allTasks.IndexOf(task);
        allTasks[index] = task with { Status = move.NewStatus };

        CategorizeAndFilter();
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
        CategorizeAndFilter();
    }
}

