@* A single Kanban column displaying its header, task cards, and an add-task form toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => HandleMoveLeft(task)"
                          OnMoveRight="() => HandleMoveRight(task)" />
            }

            @if (showAddForm)
            {
                <AddTaskForm Status="@Status"
                             TaskService="TaskService"
                             OnTaskCreated="HandleTaskCreated"
                             OnCancel="() => showAddForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = default!;

    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public string? LeftStatus { get; set; }

    [Parameter]
    public string? RightStatus { get; set; }

    [Parameter]
    public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private bool showAddForm;

    private async Task HandleMoveLeft(TaskItem task)
    {
        if (LeftStatus is not null)
        {
            await OnTaskMoved.InvokeAsync((task.Id, LeftStatus));
        }
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        if (RightStatus is not null)
        {
            await OnTaskMoved.InvokeAsync((task.Id, RightStatus));
        }
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        showAddForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

